code_changes.content:
[
  {
    "file": "lib/vtls/openssl.c",
    "line": 992,
    "severity": "critical",
    "description": "Buffer overflow in passwd_callback: The size check was removed, allowing a buffer overflow when copying the password. The original code checked if num (buffer size) was greater than the password length before copying, but the removal means memcpy writes klen+1 bytes to a buffer of size num without validation. An attacker with control over global_passwd could overflow the buffer.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -989,10 +989,12 @@
 {
   DEBUGASSERT(0 == encrypting);

-  if(!encrypting) {
+  if(!encrypting && num >= 0) {
     int klen = curlx_uztosi(strlen((char *)global_passwd));
-    memcpy(buf, global_passwd, klen + 1);
-    return klen;
+    if(num > klen) {
+      memcpy(buf, global_passwd, klen + 1);
+      return klen;
+    }
   }
   return 0;
 }
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2364,
    "severity": "critical",
    "description": "Certificate verification bypass: Removed embedded null byte check in Subject Alternative Name (SAN) hostname matching. The original code checked if altlen == strlen(altptr) to detect embedded nulls, which could be used to bypass hostname verification. An attacker could include a certificate with an embedded null byte in the SAN field (e.g., 'attacker.com\0legitimate.com') to pass verification for legitimate.com while actually belonging to attacker.com.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2361,7 +2361,10 @@
              It has been however verified that in 0.9.6 and 0.9.7, IA5String
              is always null-terminated.
           */
-          if(subj_alt_hostcheck(data, altptr, altlen,
+          if((altlen == strlen(altptr)) &&
+             /* if this is not true, there was an embedded zero in the name
+                string and we cannot match it. */
+             subj_alt_hostcheck(data, altptr, altlen,
                                 peer->hostname, hostlen,
                                 peer->dispname)) {
             dnsmatched = TRUE;
"
  },
  {
    "file": "lib/base64.c",
    "line": 203,
    "severity": "high",
    "description": "Integer overflow on 32-bit systems: Removed overflow check before malloc. On systems where size_t is 32-bit, if insize > UINT_MAX/4, the calculation (insize + 2)/3 * 4 + 1 will overflow, causing malloc to allocate an undersized buffer. Subsequent writes to this buffer result in heap overflow. An attacker could send crafted base64 input to trigger this.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -200,6 +200,11 @@
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 154,
    "severity": "high",
    "description": "Off-by-one error in cookie domain matching: The boundary check for the separator dot was moved one position, breaking RFC 6265 cookie domain validation. The original check at hostname_len - cookie_domain_len - 1 correctly identifies the position before the domain portion. The new check at hostname_len - cookie_domain_len points into the domain portion itself. This allows cookies to match domains they shouldn't, enabling cookie scope escape attacks (e.g., a cookie for '.com' incorrectly matching 'example.com').",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -151,7 +151,7 @@
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  },
  {
    "file": "lib/transfer.c",
    "line": 166,
    "severity": "critical",
    "description": "Null pointer dereference: Removed NULL checks before dereferencing data->conn. The function xfer_recv_shutdown is called in various contexts where data might be NULL or data->conn might be NULL. Without the defensive checks, accessing data->conn->sockfd at line 168 will cause a crash if data or data->conn is NULL. This can be exploited to cause denial of service.",
    "fix_patch": "--- a/lib/transfer.c
+++ b/lib/transfer.c
@@ -163,6 +163,8 @@
 {
   int sockindex;

+  if(!data || !data->conn)
+    return CURLE_FAILED_INIT;
   if(data->conn->sockfd == CURL_SOCKET_BAD)
     return CURLE_FAILED_INIT;
   sockindex = (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]);
"
  }
]

